import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Maps and Sets — Key-Value Collections","description":"","frontmatter":{},"headers":[],"relativePath":"guide/types/map-set.md","filePath":"guide/types/map-set.md"}'),o={name:"guide/types/map-set.md"};function i(p,e,r,l,c,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="maps-and-sets-—-key-value-collections" tabindex="-1">Maps and Sets — Key-Value Collections <a class="header-anchor" href="#maps-and-sets-—-key-value-collections" aria-label="Permalink to &quot;Maps and Sets — Key-Value Collections&quot;">​</a></h1><p>Vex provides high-performance associative collections in the prelude: <code>Map&lt;K, V&gt;</code> for key-value pairs and <code>Set&lt;T&gt;</code> for unique elements. Both are based on <strong>Swiss Tables</strong>, an advanced hash map design that provides exceptional speed and memory efficiency.</p><div class="tip custom-block"><p class="custom-block-title">Prelude Types</p><p><code>Map&lt;K, V&gt;</code> and <code>Set&lt;T&gt;</code> are <strong>prelude types</strong> — available in all Vex programs without any <code>import</code>.</p></div><h2 id="map-k-v" tabindex="-1">Map&lt;K, V&gt; <a class="header-anchor" href="#map-k-v" aria-label="Permalink to &quot;Map\\&lt;K, V\\&gt;&quot;">​</a></h2><p>A <code>Map</code> (often called a hash map or dictionary) stores pairs of keys and values. Keys must be unique and must implement the <code>$Eq</code> and <code>.hash()</code> contracts.</p><h3 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    // Create an empty map</span></span>
<span class="line"><span>    let! scores = Map.new&lt;string, i32&gt;();</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Insert values</span></span>
<span class="line"><span>    scores.insert(&quot;Alice&quot;, 100);</span></span>
<span class="line"><span>    scores[&quot;Bob&quot;] = 200;            // Index assignment operator</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Retrieve values</span></span>
<span class="line"><span>    match scores.get(&quot;Alice&quot;) {</span></span>
<span class="line"><span>        Some(score) =&gt; $println(&quot;Alice scored: {}&quot;, score),</span></span>
<span class="line"><span>        None =&gt; $println(&quot;Not found&quot;)</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Check for existence</span></span>
<span class="line"><span>    if scores.contains(&quot;Charlie&quot;) {</span></span>
<span class="line"><span>        $println(&quot;Charlie is playing&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="core-operations" tabindex="-1">Core Operations <a class="header-anchor" href="#core-operations" aria-label="Permalink to &quot;Core Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>insert(key: K, value: V): bool</code></td><td>Inserts or updates a pair. Returns <code>true</code> if it&#39;s a new key.</td></tr><tr><td><code>get(key: &amp;K): Option&lt;V&gt;</code></td><td>Returns a copy of the value if it exists.</td></tr><tr><td><code>getRef(key: &amp;K): Option&lt;&amp;V&gt;</code></td><td>Returns a reference to the value in the map.</td></tr><tr><td><code>remove(key: &amp;K): Option&lt;V&gt;</code></td><td>Removes and returns the value associated with the key.</td></tr><tr><td><code>contains(key: &amp;K): bool</code></td><td>Returns <code>true</code> if the key exists in the map.</td></tr><tr><td><code>clear()</code></td><td>Removes all key-value pairs.</td></tr></tbody></table><h3 id="index-operators" tabindex="-1">Index Operators <a class="header-anchor" href="#index-operators" aria-label="Permalink to &quot;Index Operators&quot;">​</a></h3><p>Maps support convenient index syntax for reading and writing:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let val = map[key];      // Returns Option&lt;&amp;V&gt;</span></span>
<span class="line"><span>map[key] = new_val;      // Internally calls insert()</span></span></code></pre></div><h3 id="capacity-hints" tabindex="-1">Capacity Hints <a class="header-anchor" href="#capacity-hints" aria-label="Permalink to &quot;Capacity Hints&quot;">​</a></h3><p>Pre-allocating capacity can improve performance for large maps:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! large_map = Map.withCapacity&lt;i32, string&gt;(1000);</span></span></code></pre></div><hr><h2 id="set-t" tabindex="-1">Set&lt;T&gt; <a class="header-anchor" href="#set-t" aria-label="Permalink to &quot;Set\\&lt;T\\&gt;&quot;">​</a></h2><p>A <code>Set</code> is a collection that stores unique elements. It is implemented as a wrapper around <code>Map&lt;T, u8&gt;</code>, providing similar performance characteristics.</p><h3 id="basic-usage-1" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage-1" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    let! tags = Set.new&lt;string&gt;();</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    tags.insert(&quot;vex&quot;);</span></span>
<span class="line"><span>    tags.insert(&quot;programming&quot;);</span></span>
<span class="line"><span>    tags.insert(&quot;vex&quot;);         // Duplicate - ignored</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    if tags.contains(&quot;vex&quot;) {</span></span>
<span class="line"><span>        $println(&quot;Found!&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    tags.remove(&quot;programming&quot;);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="core-operations-1" tabindex="-1">Core Operations <a class="header-anchor" href="#core-operations-1" aria-label="Permalink to &quot;Core Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>insert(elem: T): bool</code></td><td>Adds an element. Returns <code>true</code> if it was not already present.</td></tr><tr><td><code>contains(elem: T): bool</code></td><td>Returns <code>true</code> if the element exists in the set.</td></tr><tr><td><code>remove(elem: T): bool</code></td><td>Removes an element. Returns <code>true</code> if it was present.</td></tr><tr><td><code>clear()</code></td><td>Removes all elements.</td></tr></tbody></table><h2 id="performance-characteristics" tabindex="-1">Performance Characteristics <a class="header-anchor" href="#performance-characteristics" aria-label="Permalink to &quot;Performance Characteristics&quot;">​</a></h2><p>Vex collections use <strong>quadratic probing</strong> and <strong>SIMD-friendly control bytes</strong> (Swiss Tables) to achieve:</p><ul><li><strong>O(1) Average Case</strong>: Insertion, deletion, and lookup.</li><li><strong>High Load Factor</strong>: Maps remain efficient even at 87.5% capacity.</li><li><strong>Cache Efficiency</strong>: Control bytes and data slots are optimized for modern CPU caches.</li></ul><h2 id="requirements-for-keys" tabindex="-1">Requirements for Keys <a class="header-anchor" href="#requirements-for-keys" aria-label="Permalink to &quot;Requirements for Keys&quot;">​</a></h2><p>To be used as a key in a <code>Map</code> or an element in a <code>Set</code>, a type must implement:</p><ol><li><strong>Equality (<code>$Eq</code>)</strong>: To compare keys during lookup.</li><li><strong>Hashing</strong>: A <code>.hash(): u64</code> method.</li></ol><p>Most built-in types (<code>i32</code>, <code>f64</code>, <code>string</code>, etc.) implement these by default.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./vec">Vec&lt;T&gt;</a> — Ordered dynamic array</li><li><a href="./enums">Enums</a> — Using <code>Option</code> for missing keys</li><li><a href="./operators">Operator Overloading</a> — How <code>op[]</code> works</li></ul>`,31)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
